import{c as a,Q as o,j as e,m as n}from"./chunks/framework.DpF7k2f3.js";const m=JSON.parse('{"title":"第4章 Pythonとエンジニアリング基礎","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ja/part2-fundamentals/chapter4.md","filePath":"ja/part2-fundamentals/chapter4.md"}'),r={name:"ja/part2-fundamentals/chapter4.md"};function s(l,t,p,i,c,h){return o(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="第4章-pythonとエンジニアリング基礎" tabindex="-1">第4章 Pythonとエンジニアリング基礎 <a class="header-anchor" href="#第4章-pythonとエンジニアリング基礎" aria-label="Permalink to &quot;第4章 Pythonとエンジニアリング基礎&quot;">​</a></h1><h2 id="本章で学べること" tabindex="-1">本章で学べること <a class="header-anchor" href="#本章で学べること" aria-label="Permalink to &quot;本章で学べること&quot;">​</a></h2><p>「実践的な」基礎篇へようこそ！</p><p>来这里之前、你可能看过一些Python教程——变量、数据类型、循环、関数、面向「零基础小白」那种。教える内容没有问题，但是否有种感觉：学完了还是不知道这玩意儿跟AI开发有什么关系？</p><p>これが私が解决しようとする核心的な問題です。</p><p><strong>この章はPython入門ではなく、Pythonの「AI開発スキルギャップ弥补」です。</strong> 変数が何であるかは教えません（知っているはず）、<code>if-else</code>の書き方も教えません（見たことがあるはず）。教えるのは：公司でAIに入ると第一天打开代码编辑器，那些让你头皮发麻的东西到底是个啥。</p><p>读完这章你会带走：</p><ul><li><strong>dataclass/pydantic</strong>使用场景——为什么AI代码里满屏都是这玩意儿</li><li><strong>asyncio异步编程</strong>の实战套路——批量API呼び出し必须有技能</li><li><strong>类型注解</strong>的正确用法——让Copilot真正帮到你</li><li><strong>健壮的HTTPクライアント封装</strong>——大模型API调用のストリーミング、リトライ、タイムアウト</li><li><strong>Gitワークフロー</strong>的正确姿势——monorepo、pre-commit、.env安全</li><li><strong>2026年の環境管理方案</strong>——uv凭什么这么火</li><li><strong>GPUサーバーサバイバルスキル</strong>——查日志、看进程、调资源不求人</li></ul><hr><blockquote><p><strong>全文の翻訳は後日公開予定、しばらくお待ちください。中文版は今すぐ読めます。</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part2-fundamentals/chapter4.html">中文版阅读</a></p></blockquote>',10)])])}const u=a(r,[["render",s]]);export{m as __pageData,u as default};
